const client_id = 'YOUR_CLIENT_ID';
const client_secret = 'YOUR_CLIENT_SECRET';
const redirect_uri = 'YOUR_REDIRECT_URI';
const authorization_endpoint = 'YOUR_AUTHORIZATION_ENDPOINT';
const token_endpoint = 'YOUR_TOKEN_ENDPOINT';

const handleLogin = () => {
  const authUrl = `${authorization_endpoint}?client_id=${client_id}&redirect_uri=${redirect_uri}&response_type=code`;
  window.location.href = authUrl;
};

const handleCallback = () => {
  const code = new URLSearchParams(window.location.search).get('code');
  fetch(token_endpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: new URLSearchParams({
      client_id,
      client_secret,
      code,
      redirect_uri
    })
  })
    .then(response => response.json())
    .then(data => {
      localStorage.setItem('access_token', data.access_token);
      localStorage.setItem('refresh_token', data.refresh_token);
    });
};

const makeApiRequest = (url) => {
  const accessToken = localStorage.getItem('access_token');
  fetch(url, {
    headers: {
      Authorization: `Bearer ${accessToken}`
    }
  });
};

export default { handleLogin, makeApiRequest };